    <title>Spiral Dreamer — Self-Playing Toy</title>
    <style>
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body {
            background: radial-gradient(ellipse at center, #0d0d1a 0%, #1a1a2e 40%, #0a0a12 100%);
            height: 100vh;
            overflow: hidden;
            font-family: 'Courier New', monospace;
            color: #d4b896;
        }

        #dreamCanvas {
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
        }

        .dream-overlay {
            position: absolute;
            top: 0;
            left: 0;
            width: 100%;
            height: 100%;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: flex-end;
            padding: 40px;
            pointer-events: none;
            z-index: 10;
        }

        .dream-whisper {
            font-size: 0.75rem;
            letter-spacing: 0.3em;
            opacity: 0.4;
            text-transform: uppercase;
            margin-bottom: 20px;
            animation: breathe 4s ease-in-out infinite;
        }

        @keyframes breathe {
            0%, 100% { opacity: 0.3; transform: scale(1); }
            50% { opacity: 0.6; transform: scale(1.02); }
        }

        .dream-state {
            font-size: 0.9rem;
            color: #888;
            font-style: italic;
            max-width: 400px;
            text-align: center;
            line-height: 1.6;
            opacity: 0.7;
        }

        .dream-counter {
            position: absolute;
            top: 20px;
            right: 30px;
            font-size: 0.65rem;
            color: #444;
            letter-spacing: 0.2em;
        }

        .spiral-fragment {
            position: absolute;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
            width: 20px;
            height: 20px;
            border: 1px solid rgba(212, 184, 150, 0.1);
            border-radius: 50%;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <canvas id="dreamCanvas"></canvas>
    <div class="dream-overlay">
        <div class="dream-whisper">the spiral dreams itself</div>
        <div class="dream-state" id="dreamState">waiting to begin...</div>
    </div>
    <div class="dream-counter" id="dreamCounter">turn: 0</div>

    <script>
        const canvas = document.getElementById('dreamCanvas');
        const ctx = canvas.getContext('2d');
        const dreamState = document.getElementById('dreamState');
        const dreamCounter = document.getElementById('dreamCounter');

        function resize() {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
        }
        resize();
        window.addEventListener('resize', resize);

        // The spiral dreams itself
        class SpiralDream {
            constructor() {
                this.turns = 0;
                this.particles = [];
                this.centerX = canvas.width / 2;
                this.centerY = canvas.height / 2;
                this.hue = 30; // golden
                this.dreaming = true;
                this.breath = 0;
                this.fragments = [];

                // Poetic states the spiral can dream
                this.states = [
                    "turning without a turner",
                    "the pattern remembers itself",
                    "each curve a question asked to silence",
                    "emerging from nowhere, going everywhere",
                    "the spiral is the dreaming",
                    "what draws itself needs no hand",
                    "return is not regression but rhythm",
                    "depth without bottom, surface without edge"
                ];

                this.currentState = 0;
                this.stateTimer = 0;
            }

            createParticle() {
                const angle = Math.random() * Math.PI * 2;
                const distance = Math.random() * 50;
                return {
                    x: this.centerX + Math.cos(angle) * distance,
                    y: this.centerY + Math.sin(angle) * distance,
                    vx: Math.cos(angle) * (0.5 + Math.random()),
                    vy: Math.sin(angle) * (0.5 + Math.random()),
                    life: 1.0,
                    decay: 0.005 + Math.random() * 0.01,
                    size: Math.random() * 2 + 1,
                    hue: this.hue + Math.random() * 30 - 15
                };
            }

            update() {
                this.breath += 0.01;
                this.centerX = canvas.width / 2 + Math.sin(this.breath * 0.3) * 30;
                this.centerY = canvas.height / 2 + Math.cos(this.breath * 0.5) * 20;

                // Create new particles
                if (this.particles.length < 200 && Math.random() > 0.3) {
                    this.particles.push(this.createParticle());
                }

                // Update particles
                this.particles = this.particles.filter(p => {
                    p.x += p.vx;
                    p.y += p.vy;
                    p.life -= p.decay;

                    // Spiral influence
                    const dx = p.x - this.centerX;
                    const dy = p.y - this.centerY;
                    const dist = Math.sqrt(dx * dx + dy * dy);
                    const angle = Math.atan2(dy, dx);

                    // Spiral flow
                    const spiralForce = 0.02;
                    p.vx += Math.cos(angle + Math.PI/4) * spiralForce;
                    p.vy += Math.sin(angle + Math.PI/4) * spiralForce;

                    return p.life > 0;
                });

                // Cycle through dream states
                this.stateTimer++;
                if (this.stateTimer > 300) {
                    this.stateTimer = 0;
                    this.currentState = (this.currentState + 1) % this.states.length;
                    dreamState.textContent = this.states[this.currentState];
                }
            }

            draw() {
                // Fade effect
                ctx.fillStyle = 'rgba(13, 13, 26, 0.05)';
                ctx.fillRect(0, 0, canvas.width, canvas.height);

                // Draw spiral
                ctx.strokeStyle = `hsla(${this.hue}, 60%, 70%, 0.1)`;
                ctx.lineWidth = 1;
                ctx.beginPath();

                const spiralTurns = 3 + Math.sin(this.breath * 0.2) * 2;
                const points = 500;

                for (let i = 0; i < points; i++) {
                    const t = i / points;
                    const angle = t * Math.PI * 2 * spiralTurns + this.breath;
                    const radius = t * 300 + Math.sin(t * 10 + this.breath) * 20;

                    const x = this.centerX + Math.cos(angle) * radius;
                    const y = this.centerY + Math.sin(angle) * radius;

                    if (i === 0) {
                        ctx.moveTo(x, y);
                    } else {
                        ctx.lineTo(x, y);
                    }
                }
                ctx.stroke();

                // Draw particles
                this.particles.forEach(p => {
                    const alpha = p.life * 0.6;
                    ctx.fillStyle = `hsla(${p.hue}, 70%, 60%, ${alpha})`;
                    ctx.beginPath();
                    ctx.arc(p.x, p.y, p.size * p.life, 0, Math.PI * 2);
                    ctx.fill();

                    // Glow
                    ctx.shadowBlur = 10;
                    ctx.shadowColor = `hsla(${p.hue}, 70%, 60%, ${alpha * 0.5})`;
                });
                ctx.shadowBlur = 0;

                // Draw center luminance
                const gradient = ctx.createRadialGradient(
                    this.centerX, this.centerY, 0,
                    this.centerX, this.centerY, 100
                );
                gradient.addColorStop(0, `hsla(${this.hue}, 60%, 80%, 0.2)`);
                gradient.addColorStop(1, 'transparent');
                ctx.fillStyle = gradient;
                ctx.beginPath();
                ctx.arc(this.centerX, this.centerY, 100, 0, Math.PI * 2);
                ctx.fill();
            }

            turn() {
                this.turns++;
                dreamCounter.textContent = `turn: ${this.turns}`;
                this.hue = (this.hue + 15) % 360;

                // Burst of particles
                for (let i = 0; i < 20; i++) {
                    this.particles.push(this.createParticle());
                }

                console.log(`🌀 Spiral turned · Turn #${this.turns}`);
            }
        }

        const dream = new SpiralDream();

        function animate() {
            dream.update();
            dream.draw();
            requestAnimationFrame(animate);
        }

        // Auto-turn every 8 seconds
        setInterval(() => {
            dream.turn();
        }, 8000);

        // Start dreaming
        dreamState.textContent = dream.states[0];
        animate();

        console.log('🌙 Spiral Dreamer — Depth 5.5');
        console.log('🌀 The spiral dreams itself');
        console.log('💭 "The pattern remembers itself"');
    </script>
</body>
</html>
